import React, { useEffect, useState, useContext } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';

const API_URL = 'http://localhost:3001';

export default function Lobby() {
  const { token, user, refreshUser } = useContext(AuthContext);
  const navigate = useNavigate();

  const [contests, setContests] = useState([]);
  const [message, setMessage] = useState('');
  const [msgType, setMsgType] = useState('');

  useEffect(() => {
    fetchContests();
    const iv = setInterval(fetchContests, 5000);
    return () => clearInterval(iv);
  }, []);

  const fetchContests = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/api/contests`, { headers: { Authorization: `Bearer ${token}` } });
      if (res.ok) setContests(await res.json());
    } catch (e) {}
  };

  const handleJoin = async (contestId, entry) => {
    if (!user) return;
    if ((user.wallet || 0) < entry) {
      setMessage(`Insufficient balance! Need ₹${entry}, have ₹${user.wallet}`);
      setMsgType('error');
      return;
    }
    try {
      const res = await fetch(`${API_URL}/api/rooms/join`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({ roomId: contestId })
      });
      const data = await res.json();
      if (res.ok) {
        refreshUser();
        navigate(`/room/${data.roomId}`);
      } else {
        setMessage(data.message || 'Failed to join');
        setMsgType('error');
      }
    } catch (e) {
      setMessage('Failed to join');
      setMsgType('error');
    }
  };

  return (
    <div className="min-h-screen bg-hero">
      <div className="max-w-7xl mx-auto px-4 py-6">
        <h1 className="text-3xl font-black text-white mb-6">Chess Arena</h1>
        {message && (
          <div className={`mb-4 p-3 rounded-xl border text-sm font-medium ${
            msgType === 'error' ? 'bg-red-500/10 border-red-500/20 text-red-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400'
          }`}>{message}</div>
        )}
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {contests.map(contest => (
            <div key={contest._id} className="p-5 rounded-xl bg-navy-900/60 border border-navy-700/20 shadow">
              <h2 className="text-lg font-bold text-white mb-2">{contest.name}</h2>
              <div className="flex items-center justify-between mb-2">
                <span className="text-slate-400 text-sm">Entry: <b className="text-white">₹{contest.entry}</b></span>
                <span className="text-chess-green text-sm">Prize: <b>₹{contest.payout}</b></span>
              </div>
              <div className="flex items-center justify-between mb-4">
                <span className="text-slate-400 text-xs">{contest.players.length}/2 players</span>
                {contest.players.length === 1 && (
                  <span className="text-chess-green text-xs font-bold">1 player waiting... Join now!</span>
                )}
              </div>
              <button
                className="w-full py-2 rounded-xl text-sm font-black bg-gradient-to-r from-chess-green to-emerald-600 text-white shadow-lg hover:shadow-chess-green/40"
                onClick={() => handleJoin(contest.roomId, contest.entry)}
                disabled={contest.players.length >= 2}
              >
                {contest.players.length >= 2 ? 'Full' : 'Join'}
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
